```tsx
import { NextRequest } from 'next/server'

class NextRequest extends Request {
  cookies: RequestCookies
  nextUrl: NextURL
  ip?: string
  geo?: { city, country, region, latitude, longitude }
}
```
Extends the Web `Request` API with additional Next.js-specific properties. Used in Middleware and Route Handlers.

```tsx
fetch(url: string, {
  cache?: 'force-cache' | 'no-store',
  next?: { revalidate?: number | false, tags?: string[] }
}): Promise<Response>
```
Next.js extends the native `fetch` API with caching and revalidation options. `cache: 'force-cache'` caches indefinitely. `next.revalidate` sets time-based revalidation in seconds.

```tsx
import { unstable_cache } from 'next/cache'

const getCachedData = unstable_cache(
  async () => { /* fetch data */ },
  keyParts?: string[],
  options?: { revalidate?: number, tags?: string[] }
)
```
Wraps a function with caching. The result is cached and can be revalidated by time or tags. Useful for caching database queries and other non-fetch data sources.

```tsx
// next.config.js
module.exports = {
  images: {
    remotePatterns: [{ protocol, hostname, port, pathname }],
    domains: string[],
    formats: ('image/avif' | 'image/webp')[],
    deviceSizes: number[],
    imageSizes: number[]
  }
}
```
Configures the Next.js Image Optimization API. Define allowed remote image sources, supported formats, and responsive breakpoints.

```tsx
// next.config.js
module.exports = {
  async redirects(): Promise<Redirect[]> {
    return [{ source: '/old', destination: '/new', permanent: true }]
  }
}
```
Defines URL redirects. Each redirect has `source` (incoming path pattern), `destination` (target path), and `permanent` (308 vs 307 status code).

```tsx
// next.config.js
module.exports = {
  async rewrites() {
    return [{ source: '/api/:path*', destination: 'https://backend.example.com/:path*' }]
  }
}
```
Rewrites map an incoming request path to a different destination path. Unlike redirects, rewrites act as a URL proxy and mask the destination path.

```tsx
// next.config.js
module.exports = {
  env: { CUSTOM_KEY: 'value' }
}
```
Exposes environment variables to the browser bundle at build time. Variables prefixed with `NEXT_PUBLIC_` are automatically exposed without this config.

```tsx
// next.config.js
module.exports = {
  webpack: (config: WebpackConfig, { buildId, dev, isServer, defaultLoaders, nextRuntime, webpack }) => {
    return config
  }
}
```
Custom webpack configuration function. Called twice: once for the server and once for the client. Use to add loaders, plugins, or modify the config.

```tsx
// next.config.js
module.exports = {
  experimental: {
    turbo: {
      rules: { '*.svg': { loaders: ['@svgr/webpack'], as: '*.js' } },
      resolveAlias: { underscore: 'lodash' }
    }
  }
}
```
Turbopack configuration for the Next.js dev server (`next dev --turbo`). Supports custom loaders and module resolution aliases.

```tsx
export const metadata: Metadata = {
  metadataBase: new URL('https://example.com')
}
```
Sets the base URL for metadata fields that require a fully qualified URL (like Open Graph images). Resolves relative URLs in `openGraph`, `twitter`, and other metadata fields.

```tsx
robots: {
  index: boolean,
  follow: boolean,
  nocache: boolean,
  googleBot: { index, follow, noimageindex, 'max-video-preview', 'max-image-preview', 'max-snippet' }
}
```
Robots metadata for search engine crawling directives. Generates the `robots` meta tag.

```tsx
// app/sitemap.ts
import type { MetadataRoute } from 'next'

export default function sitemap(): MetadataRoute.Sitemap {
  return [{ url: 'https://example.com', lastModified: new Date(), changeFrequency: 'yearly', priority: 1 }]
}
```
Generates a `sitemap.xml` file for search engine discoverability. Export a default function from `app/sitemap.ts`.

```tsx
// app/manifest.ts
import type { MetadataRoute } from 'next'

export default function manifest(): MetadataRoute.Manifest {
  return { name: 'App', short_name: 'App', start_url: '/', display: 'standalone' }
}
```
Generates a `manifest.json` / `manifest.webmanifest` for Progressive Web App (PWA) support.

```tsx
export default function Layout({
  children,
  analytics,
  team
}: {
  children: React.ReactNode
  analytics: React.ReactNode
  team: React.ReactNode
}) { ... }
```
Slots are the props passed to a layout from parallel routes (`@folder`). Each slot renders independently and can have its own loading, error, and not-found states.

```tsx
import type { GetServerSideProps } from 'next'

export const getServerSideProps: GetServerSideProps = async (context) => {
  return { props: {} }
}
```
Pages Router data fetching function. Runs on every request on the server side. Can return `props`, `redirect`, or `notFound`. The page receives returned props as component props.

```tsx
import type { GetStaticProps } from 'next'

export const getStaticProps: GetStaticProps = async (context) => {
  return { props: {}, revalidate?: number }
}
```
Pages Router data fetching for static generation. Runs at build time. Supports ISR with `revalidate`. Returns `props`, `redirect`, `notFound`, or `revalidate`.

```tsx
import type { GetStaticPaths } from 'next'

export const getStaticPaths: GetStaticPaths = async () => {
  return { paths: [{ params: { id: '1' } }], fallback: false | true | 'blocking' }
}
```
Pages Router function for defining dynamic routes to pre-render at build time. Used with `getStaticProps`. `fallback` controls behavior for non-generated paths.

```tsx
export const config = {
  matcher: string | string[]
}
```
Middleware configuration object. The `matcher` property defines which routes the middleware should run on. Supports path patterns with parameters.
